const MAX_RETRIES = 2;

return $input.all().map(item => {
  // If valid, pass through unchanged
  if (item.json.validation_status === 'VALID') {
    return { json: item.json };
  }

  // Failed item — check retry count
  const retryCount = (item.json.retry_count || 0) + 1;

  if (retryCount > MAX_RETRIES) {
    return {
      json: {
        ...item.json,
        state: 'QUARANTINED',
        retry_count: retryCount,
        last_error: `Quarantined after ${MAX_RETRIES} retries. Last error: ${item.json.last_error}`,
        updated_at: new Date().toISOString()
      }
    };
  }

  return {
    json: {
      ...item.json,
      state: 'FAILED_LLM',
      retry_count: retryCount,
      updated_at: new Date().toISOString()
    }
  };
});

function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(16).padStart(8, '0');
}

function randomId() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// Get all existing hashes from sheet
const sheetRows = $input.all();
const existingItems = {};
sheetRows.forEach(row => {
  if (row.json.source_hash) {
    existingItems[row.json.source_hash] = row.json.state || '';
  }
});

// Extract items from all XML Parse outputs
const allParsed = $('XML Parse').all();
const allItems = [];

allParsed.forEach(parsed => {
  const data = parsed.json;

  if (data.rss && data.rss.channel) {
    // TechCrunch / standard RSS
    const channel = data.rss.channel;
    const items = Array.isArray(channel.item) ? channel.item : [channel.item];
    items.slice(0, 3).forEach(item => {
      const url = typeof item.link === 'object' ? item.link._ || '' : item.link || '';
      allItems.push({
        url: url,
        title: item.title || '',
        pubDate: item.pubDate || ''
      });
    });
  } else if (data.feed && data.feed.entry) {
    // YouTube Atom feed
    const entries = Array.isArray(data.feed.entry) ? data.feed.entry : [data.feed.entry];
    entries.slice(0, 2).forEach(entry => {
      const url = entry.link && entry.link.href ? entry.link.href : '';
      allItems.push({
        url: url,
        title: entry.title || '',
        pubDate: entry.published || ''
      });
    });
  }
});

return allItems.map(item => {
  const normalized = item.url.trim().toLowerCase();
  const hash = simpleHash(normalized + item.pubDate);
  const existingState = existingItems[hash] || '';
  const isNew = !existingState;

  return {
    json: {
      source_hash: hash,
      source_url: item.url,
      source_title: item.title,
      source_published_at: item.pubDate,
      correlation_id: randomId(),
      created_at: new Date().toISOString(),
      is_new: isNew,
      existing_state: existingState
    }
  };
});

return $input.all().map(item => {
  return {
    json: {
