return $input.all().map(item => {
  const html = item.json.data || '';

  const pipelineFields = {
    source_hash: item.json.source_hash,
    source_url: item.json.source_url,
    source_title: item.json.source_title,
    source_published_at: item.json.source_published_at,
    correlation_id: item.json.correlation_id,
    created_at: item.json.created_at,
    state: item.json.state,
    retry_count: item.json.retry_count,
    last_error: item.json.last_error,
    prompt_version: item.json.prompt_version,
    model: item.json.model,
    llm_output_raw: item.json.llm_output_raw,
    validation_status: item.json.validation_status,
    generation_attempt: item.json.generation_attempt,
    approval_form_url: item.json.approval_form_url,
    approved_by: item.json.approved_by,
    approved_at: item.json.approved_at,
    published_at: item.json.published_at,
    draft_destination_url: item.json.draft_destination_url,
    updated_at: item.json.updated_at,
  };

  if (!html || html.length < 100) {
    return {
      json: {
        ...pipelineFields,
        article_body: '',
        article_fetch_status: 'FAILED',
      }
    };
  }

  let text = html.replace(/<(script|style|noscript|head|meta|link)[\s>][^]*?<\/\1>/gi, '');
  text = text.replace(/<[^>]+>/g, ' ');
  text = text
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, ' ')
    .replace(/&#(\d+);/g, (match, dec) => String.fromCharCode(dec))
.replace(/&#x([0-9a-f]+);/gi, (match, hex) => String.fromCharCode(parseInt(hex, 16)));

  text = text
    .split('\n')
    .map(line => line.replace(/[ \t]+/g, ' ').trim())
    .filter(line => line.length > 0)
    .join('\n');

  text = text.replace(/\n{3,}/g, '\n\n').trim();

  if (text.replace(/\s/g, '').length < 100) {
    return {
      json: {
        ...pipelineFields,
        article_body: '',
        article_fetch_status: 'FAILED',
      }
    };
  }

  const truncated = text.length > 3000 ? text.slice(0, 3000) + '...' : text;

  return {
    json: {
      ...pipelineFields,
      article_body: truncated,
      article_fetch_status: 'SUCCESS',
    }
  };
});

return $input.all().map(item => {
  const title = item.json.source_title || '';
  const url = item.json.source_url || '';
  const pubDate = item.json.source_published_at || '';
  const articleBody = item.json.article_body || '';
  const fetchStatus = item.json.article_fetch_status || 'FAILED';

  const cleanTitle = title
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 200);

  // Include article body if fetch succeeded, fall back to title-only
  const contentBlock = fetchStatus === 'SUCCESS' && articleBody
    ? `Title: ${cleanTitle}\nPublished: ${pubDate}\nURL: ${url}\n\nArticle Body:\n${articleBody}`
    : `Title: ${cleanTitle}\nPublished: ${pubDate}\nURL: ${url}`;

  return {
    json: {
      ...item.json,
      preprocessed_content: contentBlock,
      state: 'PREPROCESSED',
      updated_at: new Date().toISOString()
    }
  };
});

return $input.all().map(item => {
  const content = item.json.preprocessed_content;

  const body = {
    model: "gpt-4o-mini",
    max_tokens: 1000,
    messages: [
      {
        role: "system",
        content: "You are a content repurposing assistant. Given an article title, metadata, and full article body, generate multi-channel marketing content. You must respond with valid JSON only. No prose, no markdown, no code fences. Only the JSON object."
      },
      {
        role: "user",
        content: `${content}\n\nRespond with a JSON object containing exactly these fields:\n{\n  "twitter_thread": ["tweet 1", "tweet 2", "tweet 3"],\n  "linkedin_post": "string, max 1300 chars",\n  "newsletter": "string, max 500 chars",\n  "title_options": ["option 1", "option 2", "option 3"],\n  "hashtags": ["tag1", "tag2", "tag3", "tag4", "tag5"]\n}`
      }
    ]
  };

  return {
    json: {
      source_hash: item.json.source_hash,
      source_url: item.json.source_url,
      source_title: item.json.source_title,
      source_published_at: item.json.source_published_at,
      correlation_id: item.json.correlation_id,
      created_at: item.json.created_at,
      state: item.json.state,
      retry_count: item.json.retry_count,
      last_error: item.json.last_error,
      prompt_version: item.json.prompt_version,
      model: item.json.model,
      llm_output_raw: item.json.llm_output_raw,
      validation_status: item.json.validation_status,
      generation_attempt: item.json.generation_attempt,
      approval_form_url: item.json.approval_form_url,
      approved_by: item.json.approved_by,
      approved_at: item.json.approved_at,
      published_at: item.json.published_at,
      draft_destination_url: item.json.draft_destination_url,
      article_body: item.json.article_body,
      article_fetch_status: item.json.article_fetch_status,
      preprocessed_content: item.json.preprocessed_content,
      request_body: body
    }
  };
});

const REQUIRED_FIELDS = ['twitter_thread', 'linkedin_post', 'newsletter', 'title_options', 'hashtags'];

return $input.all().map(item => {
  const upstream = $('Build OpenAI Request').item.json;

const pipelineFields = {
  source_hash: upstream.source_hash,
  source_url: upstream.source_url,
  source_title: upstream.source_title,
  source_published_at: upstream.source_published_at,
  correlation_id: upstream.correlation_id,
  created_at: upstream.created_at,
  state: upstream.state,
  retry_count: upstream.retry_count,
  last_error: upstream.last_error,
  prompt_version: upstream.prompt_version,
  model: upstream.model,
  llm_output_raw: upstream.llm_output_raw,
  validation_status: upstream.validation_status,
  generation_attempt: upstream.generation_attempt,
  approval_form_url: upstream.approval_form_url,
  approved_by: upstream.approved_by,
  approved_at: upstream.approved_at,
  published_at: upstream.published_at,
  draft_destination_url: upstream.draft_destination_url,
  article_body: upstream.article_body,
  article_fetch_status: upstream.article_fetch_status,
};

  const raw = item.json.choices?.[0]?.message?.content || '';
  let parsed = null;
  let lastError = '';

  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    lastError = `JSON parse failed: ${e.message}`;
    return {
      json: {
        ...pipelineFields,
        llm_output_raw: raw,
        validation_status: 'INVALID',
        last_error: lastError,
        state: 'FAILED_LLM',
        updated_at: new Date().toISOString()
      }
    };
  }

  const missingFields = REQUIRED_FIELDS.filter(f => !(f in parsed));
  if (missingFields.length > 0) {
    lastError = `Missing fields: ${missingFields.join(', ')}`;
    return {
      json: {
        ...pipelineFields,
        llm_output_raw: raw,
        validation_status: 'INVALID',
        last_error: lastError,
        state: 'FAILED_LLM',
        updated_at: new Date().toISOString()
      }
    };
  }

  if (!Array.isArray(parsed.twitter_thread)) lastError += 'twitter_thread must be array. ';
  if (typeof parsed.linkedin_post !== 'string') lastError += 'linkedin_post must be string. ';
  if (typeof parsed.newsletter !== 'string') lastError += 'newsletter must be string. ';
  if (!Array.isArray(parsed.title_options)) lastError += 'title_options must be array. ';
  if (!Array.isArray(parsed.hashtags)) lastError += 'hashtags must be array. ';

  if (lastError) {
    return {
      json: {
        ...pipelineFields,
        llm_output_raw: raw,
        validation_status: 'INVALID',
        last_error: lastError.trim(),
        state: 'FAILED_LLM',
        updated_at: new Date().toISOString()
      }
    };
  }

  return {
    json: {
      ...pipelineFields,
      llm_output_raw: raw,
      twitter_thread: parsed.twitter_thread,
      linkedin_post: parsed.linkedin_post,
      newsletter: parsed.newsletter,
      title_options: parsed.title_options,
      hashtags: parsed.hashtags.map(tag => tag.startsWith('#') ? tag : '#' + tag),
      validation_status: 'VALID',
      last_error: '',
      state: 'GENERATED',
      generation_attempt: (item.json.generation_attempt || 0) + 1,
      updated_at: new Date().toISOString()
    }
  };
});

