return $input.all().map(item => {
  const title = item.json.source_title || 'Untitled';
  const hash = item.json.source_hash;
  const url = item.json.source_url || '';
  const pubDate = item.json.source_published_at || '';

  let parsed = {};
  try {
    parsed = JSON.parse(item.json.llm_output_raw || '{}');
  } catch(e) {
    parsed = {};
  }

  const twitterThread = parsed.twitter_thread || [];
  const linkedinPost = parsed.linkedin_post || '';
  const newsletter = parsed.newsletter || '';
  const titleOptions = parsed.title_options || [];
  const hashtags = parsed.hashtags || [];

  const docContent = `
CONTENT DRAFT — ${title}
Generated by content-pipeline-v0.1

Source URL: ${url}
Published: ${pubDate}
Source Hash: ${hash}

═══════════════════════════════════
TWITTER THREAD
═══════════════════════════════════
${twitterThread.map((t, i) => `[${i+1}] ${t}`).join('\n\n')}

═══════════════════════════════════
LINKEDIN POST
═══════════════════════════════════
${linkedinPost}

═══════════════════════════════════
NEWSLETTER DRAFT
═══════════════════════════════════
${newsletter}

═══════════════════════════════════
TITLE OPTIONS
═══════════════════════════════════
${titleOptions.map((t, i) => `${i+1}. ${t}`).join('\n')}

═══════════════════════════════════
HASHTAGS
═══════════════════════════════════
${hashtags.join(' ')}
  `.trim();

  return {
    json: {
      ...item.json,
      doc_title: `[DRAFT] ${title}`,
      doc_content: docContent
    }
  };
});

const pipelineFields = $('Init: Full Fields').item.json;
const execResult = $input.item.json;

const transcript = execResult.transcript || '';
const hasError = execResult.error && execResult.error.length > 0;

let articleBody = '';
let fetchStatus = '';

if (!hasError && transcript.trim().length > 0) {
  articleBody = transcript.trim();
  fetchStatus = 'success';
} else {
  articleBody = '';
  fetchStatus = 'failed';
}

return {
  json: {
    ...pipelineFields,
    article_body: articleBody,
    article_fetch_status: fetchStatus,
  }
};
